import { useState, useEffect, useRef } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { authService } from '../../services/auth';

const Navbar = () => {
  const navigate  = useNavigate();
  const location  = useLocation();
  const [user, setUser]           = useState(null);
  const [menuOpen, setMenuOpen]   = useState(false);
  const [dropOpen, setDropOpen]   = useState(false);
  const [scrolled, setScrolled]   = useState(false);
  const dropRef = useRef(null);

  // Load user
  useEffect(() => {
    setUser(authService.getUserFromStorage());
  }, [location.pathname]);

  // Scroll shadow
  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 10);
    window.addEventListener('scroll', onScroll);
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  // Close dropdown on outside click
  useEffect(() => {
    const handler = (e) => {
      if (dropRef.current && !dropRef.current.contains(e.target)) setDropOpen(false);
    };
    document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, []);

  // Close mobile menu on route change
  useEffect(() => { setMenuOpen(false); setDropOpen(false); }, [location.pathname]);

  const handleLogout = () => {
    authService.logout();
    setUser(null);
    navigate('/');
  };

  const isActive = (path) => location.pathname === path;

  const initials = user
    ? ((user.first_name?.[0] || '') + (user.last_name?.[0] || '')) || user.email?.[0]?.toUpperCase()
    : '';

  const dashPath = user?.is_instructor ? '/dashboard/instructor' : '/dashboard/student';

  return (
    <nav style={{ ...s.nav, ...(scrolled ? s.navScrolled : {}) }}>
      <div style={s.inner}>

        {/* ── Logo ── */}
        <Link to="/" style={s.logo}>
          <span style={s.logoIcon}>🎓</span>
          <span style={s.logoText}>Edu<span style={s.logoAccent}>Platform</span></span>
        </Link>

        {/* ── Desktop links ── */}
        <div style={s.links} className="nb-links">
          <Link to="/"        style={s.link(isActive('/'))}>الرئيسية</Link>
          <Link to="/courses" style={s.link(isActive('/courses'))}>الكورسات</Link>
          {user?.is_instructor && (
            <Link to="/courses/create" style={s.link(isActive('/courses/create'))}>+ كورس جديد</Link>
          )}
          {user?.is_staff && (
            <Link to="/admin/courses" style={s.adminLink}>🛡 الأدمن</Link>
          )}
        </div>

        {/* ── Desktop auth ── */}
        <div style={s.authArea} className="nb-auth">
          {user ? (
            <div style={s.userMenu} ref={dropRef}>
              {/* Avatar button */}
              <button style={s.avatarBtn} onClick={() => setDropOpen(!dropOpen)}>
                <div style={s.avatar}>{initials}</div>
                <div style={s.userInfo}>
                  <span style={s.userName}>
                    {user.first_name || user.email?.split('@')[0]}
                  </span>
                  <span style={s.userRole}>
                    {user.is_staff ? '🛡 أدمن' : user.is_instructor ? '🎓 مدرّس' : '📚 طالب'}
                  </span>
                </div>
                <span style={{ ...s.chevron, ...(dropOpen ? s.chevronUp : {}) }}>▾</span>
              </button>

              {/* Dropdown */}
              {dropOpen && (
                <div style={s.dropdown}>
                  <div style={s.dropHeader}>
                    <p style={s.dropName}>{user.first_name} {user.last_name}</p>
                    <p style={s.dropEmail}>{user.email}</p>
                  </div>
                  <div style={s.dropDivider} />
                  <DropItem icon="📊" label="لوحة التحكم" onClick={() => navigate(dashPath)} />
                  <DropItem icon="👤" label="الملف الشخصي" onClick={() => navigate('/profile')} />
                  {user.is_instructor && (
                    <DropItem icon="➕" label="إنشاء كورس" onClick={() => navigate('/courses/create')} />
                  )}
                  {user.is_staff && (
                    <DropItem icon="🛡" label="لوحة الأدمن" onClick={() => navigate('/admin/courses')} accent />
                  )}
                  <div style={s.dropDivider} />
                  <DropItem icon="🚪" label="تسجيل الخروج" onClick={handleLogout} danger />
                </div>
              )}
            </div>
          ) : (
            <div style={s.guestBtns}>
              <Link to="/login"    style={s.loginBtn}>دخول</Link>
              <Link to="/register" style={s.registerBtn}>إنشاء حساب</Link>
            </div>
          )}
        </div>

        {/* ── Mobile hamburger ── */}
        <button style={s.hamburger} className="nb-burger" onClick={() => setMenuOpen(!menuOpen)}>
          <span style={s.bar(menuOpen, 'top')} />
          <span style={s.bar(menuOpen, 'mid')} />
          <span style={s.bar(menuOpen, 'bot')} />
        </button>
      </div>

      {/* ── Mobile menu ── */}
      {menuOpen && (
        <div style={s.mobileMenu}>
          <Link to="/"        style={s.mobileLink(isActive('/'))}>🏠 الرئيسية</Link>
          <Link to="/courses" style={s.mobileLink(isActive('/courses'))}>📚 الكورسات</Link>
          {user ? (
            <>
              <Link to={dashPath}    style={s.mobileLink(false)}>📊 لوحة التحكم</Link>
              <Link to="/profile"    style={s.mobileLink(false)}>👤 الملف الشخصي</Link>
              {user.is_instructor && <Link to="/courses/create" style={s.mobileLink(false)}>➕ كورس جديد</Link>}
              {user.is_staff      && <Link to="/admin/courses"  style={s.mobileLinkAccent}>🛡 الأدمن</Link>}
              <button style={s.mobileLinkDanger} onClick={handleLogout}>🚪 تسجيل الخروج</button>
            </>
          ) : (
            <div style={s.mobileAuthBtns}>
              <Link to="/login"    style={s.mobileLoginBtn}>دخول</Link>
              <Link to="/register" style={s.mobileRegisterBtn}>إنشاء حساب</Link>
            </div>
          )}
        </div>
      )}
    </nav>
  );
};

// ─── Dropdown item ────────────────────────────────────────────────────────────
const DropItem = ({ icon, label, onClick, danger, accent }) => (
  <button style={{
    ...s.dropItem,
    ...(danger ? s.dropItemDanger : {}),
    ...(accent ? s.dropItemAccent : {}),
  }} onClick={onClick}>
    <span>{icon}</span>
    <span>{label}</span>
  </button>
);

// ─── Styles ───────────────────────────────────────────────────────────────────
const s = {
  nav: {
    position: 'sticky', top: 0, zIndex: 200,
    background: 'rgba(15,15,26,0.85)',
    backdropFilter: 'blur(20px)',
    borderBottom: '1px solid rgba(255,255,255,0.07)',
    transition: 'box-shadow 0.3s',
    fontFamily: 'Cairo, sans-serif',
  },
  navScrolled: {
    boxShadow: '0 4px 30px rgba(0,0,0,0.4)',
  },
  inner: {
    maxWidth: 1200, margin: '0 auto',
    display: 'flex', alignItems: 'center',
    padding: '0 20px', height: 64, gap: 32,
  },

  // Logo
  logo:      { display:'flex', alignItems:'center', gap:10, textDecoration:'none', flexShrink:0 },
  logoIcon:  { fontSize:24 },
  logoText:  { color:'#fff', fontSize:18, fontWeight:800, letterSpacing:-0.5 },
  logoAccent:{ color:'#e94560' },

  // Nav links
  links: { display:'flex', alignItems:'center', gap:4, flex:1 },
  link: (active) => ({
    color: active ? '#fff' : 'rgba(255,255,255,0.5)',
    textDecoration: 'none', fontSize: 14, fontWeight: active ? 700 : 500, 
    padding: '6px 12px', borderRadius: 8,
    background: active ? 'rgba(255,255,255,0.08)' : 'transparent',
    transition: 'all 0.2s',
  }),
  adminLink: {
    color:'#f5c542', textDecoration:'none', fontSize:14, fontWeight:700,
    padding:'6px 12px', borderRadius:8,
    background:'rgba(245,197,66,0.08)',
  },

  // Auth area
  authArea: { display:'flex', alignItems:'center', flexShrink:0 },

  // Guest buttons
  guestBtns:    { display:'flex', gap:8, alignItems:'center' },
  loginBtn:     { color:'rgba(255,255,255,0.7)', textDecoration:'none', fontSize:14,
                  fontWeight:600, padding:'7px 16px', borderRadius:8,
                  border:'1px solid rgba(255,255,255,0.12)', transition:'all 0.2s' },
  registerBtn:  { background:'linear-gradient(135deg,#e94560,#c73652)', color:'#fff',
                  textDecoration:'none', fontSize:14, fontWeight:700,
                  padding:'8px 18px', borderRadius:8 },

  // User menu
  userMenu:  { position:'relative' },
  avatarBtn: { display:'flex', alignItems:'center', gap:10, background:'rgba(255,255,255,0.06)',
               border:'1px solid rgba(255,255,255,0.1)', borderRadius:10,
               padding:'6px 12px 6px 8px', cursor:'pointer', transition:'background 0.2s' },
  avatar:    { width:32, height:32, borderRadius:'50%', background:'linear-gradient(135deg,#e94560,#c73652)',
               display:'flex', alignItems:'center', justifyContent:'center',
               fontSize:13, fontWeight:800, color:'#fff', flexShrink:0 },
  userInfo:  { display:'flex', flexDirection:'column', alignItems:'flex-start' },
  userName:  { color:'#fff', fontSize:13, fontWeight:700, lineHeight:1.2 },
  userRole:  { color:'rgba(255,255,255,0.4)', fontSize:11, lineHeight:1.2 },
  chevron:   { color:'rgba(255,255,255,0.4)', fontSize:12, transition:'transform 0.2s' },
  chevronUp: { transform:'rotate(180deg)' },

  // Dropdown
  dropdown: {
    position:'absolute', top:'calc(100% + 10px)', left:0,
    background:'#1a1a2e', border:'1px solid rgba(255,255,255,0.1)',
    borderRadius:14, minWidth:220, overflow:'hidden',
    boxShadow:'0 20px 50px rgba(0,0,0,0.5)',
    animation:'fadeIn 0.15s ease',
    zIndex: 300,
  },
  dropHeader:  { padding:'14px 16px' },
  dropName:    { color:'#fff', fontWeight:700, fontSize:14, margin:'0 0 2px' },
  dropEmail:   { color:'rgba(255,255,255,0.4)', fontSize:12, margin:0 },
  dropDivider: { height:1, background:'rgba(255,255,255,0.07)', margin:'4px 0' },
  dropItem: {
    display:'flex', alignItems:'center', gap:10, width:'100%',
    padding:'10px 16px', background:'none', border:'none',
    color:'rgba(255,255,255,0.7)', fontSize:14, cursor:'pointer',
    textAlign:'right', fontFamily:'Cairo,sans-serif', transition:'background 0.15s',
  },
  dropItemDanger: { color:'#e94560' },
  dropItemAccent: { color:'#f5c542' },

  // Hamburger
  hamburger: { display:'none', flexDirection:'column', gap:5, background:'none',
               border:'none', cursor:'pointer', padding:6, marginRight: 'auto' },
  bar: (open, pos) => ({
    display:'block', width:22, height:2, background:'rgba(255,255,255,0.7)',
    borderRadius:2, transition:'all 0.3s',
    transform: open
      ? pos==='top' ? 'translateY(7px) rotate(45deg)'
      : pos==='bot' ? 'translateY(-7px) rotate(-45deg)'
      : 'scaleX(0)'
      : 'none',
    opacity: open && pos==='mid' ? 0 : 1,
  }),

  // Mobile menu
  mobileMenu: {
    background:'#13131f', borderTop:'1px solid rgba(255,255,255,0.07)',
    padding:'12px 0 20px', display:'flex', flexDirection:'column',
  },
  mobileLink: (active) => ({
    display:'block', padding:'12px 24px', color: active ? '#fff' : 'rgba(255,255,255,0.6)',
    textDecoration:'none', fontSize:15, fontWeight: active ? 700 : 500,
    background: active ? 'rgba(255,255,255,0.06)' : 'transparent',
    transition:'background 0.2s',
  }),
  mobileLinkAccent: { display:'block', padding:'12px 24px', color:'#f5c542',
                      textDecoration:'none', fontSize:15, fontWeight:700 },
  mobileLinkDanger: { display:'block', width:'100%', padding:'12px 24px', color:'#e94560',
                      background:'none', border:'none', fontSize:15, fontWeight:700,
                      textAlign:'right', cursor:'pointer', fontFamily:'Cairo,sans-serif' },
  mobileAuthBtns:   { display:'flex', gap:10, padding:'12px 24px', marginTop:4 },
  mobileLoginBtn:   { flex:1, textAlign:'center', padding:'10px', color:'rgba(255,255,255,0.7)',
                      border:'1px solid rgba(255,255,255,0.15)', borderRadius:8,
                      textDecoration:'none', fontWeight:600, fontSize:14 },
  mobileRegisterBtn:{ flex:1, textAlign:'center', padding:'10px',
                      background:'linear-gradient(135deg,#e94560,#c73652)', color:'#fff',
                      borderRadius:8, textDecoration:'none', fontWeight:700, fontSize:14 },
};

// Inject responsive styles
if (typeof document !== 'undefined' && !document.getElementById('nb-resp')) {
  const st = document.createElement('style');
  st.id = 'nb-resp';
  st.innerHTML = `
    @keyframes fadeIn { from { opacity:0; transform:translateY(-8px); } to { opacity:1; transform:translateY(0); } }
    @media (max-width: 768px) {
      .nb-links  { display: none !important; }
      .nb-auth   { display: none !important; }
      .nb-burger { display: flex !important; }
    }
  `;
  document.head.appendChild(st);
}

export default Navbar;
